const body = $input.item.json.body || {};
const filters = body.filters || {};
const page = body.page || 1;
const limit = body.limit || 10;
const offset = (page - 1) * limit;
const conditions = [];
const params = [];

if (filters.searchText && typeof filters.searchText === 'string' && filters.searchText.trim() !== '') {
  conditions.push(`(CONCAT(s.nombre, ' ', s.primer_apellido, ' ', COALESCE(s.segundo_apellido,'')) ILIKE $${params.length + 1} OR s.email ILIKE $${params.length + 1})`);
  params.push(`%${filters.searchText.trim()}%`);
}

if (filters.status !== undefined && filters.status !== null && filters.status !== '') {
  const statusStr = String(filters.status).toLowerCase();
  if (statusStr !== 'todos' && statusStr !== 'todos los estados') {
    conditions.push(`s.activo = $${params.length + 1}`);
    params.push(statusStr === 'activos' || statusStr === 'activo');
  }
}

if (filters.tipo !== undefined && filters.tipo !== null && filters.tipo !== '') {
  const tipoStr = String(filters.tipo).toLowerCase();
  if (tipoStr !== 'todos' && tipoStr !== 'todos los tipos') {
    conditions.push(`s.tipo = $${params.length + 1}`);
    params.push(tipoStr);
  }
}

let whereClause = 'WHERE 1=1';
if (conditions.length > 0) {
  whereClause += ' AND ' + conditions.join(' AND ');
}

const limitParam = params.length + 1;
const offsetParam = params.length + 2;
params.push(limit);
params.push(offset);

const query = `WITH global_stats AS (
  SELECT
    COUNT(*)::int as total,
    COUNT(*) FILTER (WHERE activo = true)::int as activos,
    COUNT(*) FILTER (WHERE activo = false)::int as inactivos,
    COUNT(*) FILTER (WHERE tipo = 'externo')::int as externos
  FROM seleccionadores
),
filtered_data AS (
  SELECT
    s.*,
    (CASE WHEN e.id IS NOT NULL THEN json_build_object('id', e.id, 'nombre', e.nombre_empresa) ELSE NULL END) as empresa
  FROM seleccionadores s
  LEFT JOIN empresa e ON s.id_empresa = e.id
  ${whereClause}
  ORDER BY s.created_at DESC
  LIMIT $${limitParam} OFFSET $${offsetParam}
),
filtered_count AS (
  SELECT COUNT(*)::int as total_filtered
  FROM seleccionadores s
  ${whereClause}
)
SELECT
  fd.*,
  fc.total_filtered,
  gs.total as stats_total,
  gs.activos as stats_activos,
  gs.inactivos as stats_inactivos,
  gs.externos as stats_externos
FROM global_stats gs
CROSS JOIN filtered_count fc
LEFT JOIN filtered_data fd ON true`;

return [{ json: { query, params } }];

