WITH updated AS (
  UPDATE seleccionadores SET activo = NOT activo, updated_at = NOW() WHERE id = $1 RETURNING *
)
SELECT u.*, (CASE WHEN e.id IS NOT NULL THEN json_build_object('id', e.id, 'nombre', e.nombre_empresa) ELSE NULL END) as empresa 
FROM updated u LEFT JOIN empresa e ON u.id_empresa = e.id;
